/// The base type tag for a Lua value. Matches C-Lua's LUA_T* constants.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
#[repr(i8)]
pub enum LuaType {
    None          = -1,
    Nil           = 0,
    Boolean       = 1,
    LightUserData = 2,
    Number        = 3,
    String        = 4,
    Table         = 5,
    Function      = 6,
    UserData      = 7,
    Thread        = 8,
}

impl LuaType {
    pub const NUM_TYPES: usize = 9;
}

